using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

// ---------------------------------------------------------------------------
// Tools the agent can invoke
// ---------------------------------------------------------------------------
var notepad = new Notepad();
var webSearch = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// ---------------------------------------------------------------------------
// Chat client with automatic function-calling
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = tools };

// ---------------------------------------------------------------------------
// Agent system prompt
// ---------------------------------------------------------------------------
var systemPrompt = """
    You are a research agent. Your job is to research a topic the user gives you
    by searching the web, saving important findings as notes, and then producing
    a concise summary.

    Workflow:
    1. Break the topic into 2-3 search queries.
    2. For each query, call the SearchWeb tool.
    3. Save key facts using the SaveNote tool.
    4. After researching, call GetNotes to review everything you collected.
    5. Produce a well-structured summary with references.

    Be thorough but concise. Always cite where information came from.
    """;

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notepad.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research this topic: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching…\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(history, chatOptions);

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine(response.Text);
    Console.ResetColor();
    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Web search tool – uses DuckDuckGo HTML search (no API key required)
// ---------------------------------------------------------------------------
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Search the web for a query and return a text snippet of results.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🔍  Searching: {query}");
        Console.ResetColor();

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            // Pull out result snippets from the HTML
            var results = new StringBuilder();
            var snippetTag = "class=\"result__snippet\"";
            var titleTag = "class=\"result__a\"";
            int count = 0, pos = 0;

            while (count < 5 && (pos = html.IndexOf(snippetTag, pos, StringComparison.Ordinal)) >= 0)
            {
                count++;
                var snippetStart = html.IndexOf('>', pos) + 1;
                var snippetEnd = html.IndexOf('<', snippetStart);
                var snippet = snippetEnd > snippetStart
                    ? StripHtml(html[snippetStart..snippetEnd])
                    : "";

                // Try to grab the title too
                var lookBack = html.LastIndexOf(titleTag, pos, Math.Min(pos, 2000), StringComparison.Ordinal);
                var title = "";
                if (lookBack >= 0)
                {
                    var tStart = html.IndexOf('>', lookBack) + 1;
                    var tEnd = html.IndexOf('<', tStart);
                    if (tEnd > tStart) title = StripHtml(html[tStart..tEnd]);
                }

                results.AppendLine($"[{count}] {title}");
                results.AppendLine($"    {snippet}");
                results.AppendLine();

                pos = snippetEnd > 0 ? snippetEnd : pos + snippetTag.Length;
            }

            return count > 0
                ? results.ToString()
                : "No results found. Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string StripHtml(string text) =>
        System.Text.RegularExpressions.Regex.Replace(
            System.Net.WebUtility.HtmlDecode(text), "<[^>]+>", "").Trim();
}

// ---------------------------------------------------------------------------
// Note-taking tool – an in-memory scratch-pad the agent uses to collect facts
// ---------------------------------------------------------------------------
sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Save an important fact or finding as a note for later summarization.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📝  Note #{_notes.Count} saved");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Get all notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

